from __future__ import annotations
import hashlib, json, time
from dataclasses import dataclass, field, asdict
from enum import Enum
from pathlib import Path
from typing import Optional

class DataRegion(str, Enum):
    EU   = "eu-west-1"
    US   = "us-east-1"
    APAC = "ap-northeast-1"

class SensitivityLabel(str, Enum):
    PUBLIC     = "PUBLIC"
    INTERNAL   = "INTERNAL"
    RESTRICTED = "RESTRICTED"
    CONFIDENTIAL = "CONFIDENTIAL"
    REGULATED  = "REGULATED"

@dataclass(frozen=True)
class RequestResidencyRecord:
    """One immutable record per GenAI API call. Written to an append-only NDJSON log."""
    request_id:        str
    tenant_id:         str
    timestamp_utc:     float                  # Unix seconds (UTC)
    data_subject_region: DataRegion           # where the data subject is located
    routed_to_region:  DataRegion             # actual endpoint region chosen
    endpoint_url:      str                    # full HTTPS URL of the LLM endpoint
    model_id:          str                    # e.g. "gpt-4o" or "claude-3-5-sonnet"
    sensitivity_label: SensitivityLabel
    is_compliant:      bool                   # routed_to_region == required_region
    violation_reason:  Optional[str] = None  # set only when is_compliant is False
    sha256_prev:       Optional[str] = None  # hash of the previous record (chain)

    def to_ndjson_line(self) -> str:
        return json.dumps(asdict(self), default=str)

    def sha256(self) -> str:
        return hashlib.sha256(self.to_ndjson_line().encode()).hexdigest()


class ResidencyAuditLog:
    """Append-only log with hash chaining for tamper evidence."""

    def __init__(self, path: Path):
        self.path = path
        self._prev_hash: Optional[str] = self._read_last_hash()

    def _read_last_hash(self) -> Optional[str]:
        if not self.path.exists():
            return None
        lines = self.path.read_text().splitlines()
        for line in reversed(lines):
            if line.strip():
                return hashlib.sha256(line.encode()).hexdigest()
        return None

    def append(self, record: RequestResidencyRecord) -> str:
        # Inject chain hash before writing
        chained = RequestResidencyRecord(
            **{k: v for k, v in asdict(record).items() if k != "sha256_prev"},
            sha256_prev=self._prev_hash,
        )
        line = chained.to_ndjson_line()
        with self.path.open("a") as f:
            f.write(line + "\n")
        self._prev_hash = hashlib.sha256(line.encode()).hexdigest()
        return self._prev_hash

    def verify_chain(self) -> tuple[bool, list[str]]:
        """Return (all_valid, list_of_errors). Errors mean tampering or corruption."""
        errors: list[str] = []
        lines = [l for l in self.path.read_text().splitlines() if l.strip()]
        prev: Optional[str] = None
        for i, line in enumerate(lines):
            rec = json.loads(line)
            if rec.get("sha256_prev") != prev:
                errors.append(f"Chain break at record {i}: expected {prev}, got {rec.get('sha256_prev')}")
            prev = hashlib.sha256(line.encode()).hexdigest()
        return (len(errors) == 0, errors)

from __future__ import annotations
import hashlib, json, shutil, zipfile
from dataclasses import dataclass, field
from datetime import date, datetime
from pathlib import Path
from typing import Optional

@dataclass
class EvidenceArtifact:
    artifact_id:   str
    category:      str            # e.g. "cloud_attestation", "soc2_report"
    filename:      str
    description:   str
    region:        str
    collected_date: date
    sha256:        str = field(init=False)
    path:          Path = field(repr=False)

    def __post_init__(self):
        self.sha256 = hashlib.sha256(self.path.read_bytes()).hexdigest()

    def to_manifest_entry(self) -> dict:
        return {
            "artifact_id":    self.artifact_id,
            "category":       self.category,
            "filename":       self.filename,
            "description":    self.description,
            "region":         self.region,
            "collected_date": str(self.collected_date),
            "sha256":         self.sha256,
        }


@dataclass
class EvidenceRegistry:
    artifacts: list[EvidenceArtifact] = field(default_factory=list)

    def register(self, artifact: EvidenceArtifact) -> None:
        if any(a.artifact_id == artifact.artifact_id for a in self.artifacts):
            raise ValueError(f"Duplicate artifact_id: {artifact.artifact_id}")
        self.artifacts.append(artifact)

    def coverage_report(self) -> dict:
        required_categories = {
            "cloud_attestation", "soc2_report", "pentest_scope",
            "dpo_attestation", "routing_log_sample", "exception_register",
        }
        covered = {a.category for a in self.artifacts}
        missing = required_categories - covered
        return {
            "total_artifacts":      len(self.artifacts),
            "categories_covered":   sorted(covered),
            "categories_missing":   sorted(missing),
            "coverage_pct":         round(100 * len(covered) / len(required_categories), 1),
            "is_audit_ready":       len(missing) == 0,
        }

    def build_audit_package(self, output_zip: Path, period_start: date, period_end: date) -> Path:
        """Build a signed ZIP containing all artifacts and a manifest.json."""
        manifest = {
            "package_version": "1.0",
            "generated_utc":   datetime.utcnow().isoformat(),
            "audit_period":    {"start": str(period_start), "end": str(period_end)},
            "artifacts":       [a.to_manifest_entry() for a in self.artifacts],
            "coverage":        self.coverage_report(),
        }
        with zipfile.ZipFile(output_zip, "w", zipfile.ZIP_DEFLATED) as zf:
            zf.writestr("manifest.json", json.dumps(manifest, indent=2))
            for a in self.artifacts:
                zf.write(a.path, arcname=f"artifacts/{a.filename}")
        # Write package hash alongside the ZIP
        pkg_hash = hashlib.sha256(output_zip.read_bytes()).hexdigest()
        output_zip.with_suffix(".sha256").write_text(f"{pkg_hash}  {output_zip.name}\n")
        return output_zip

from __future__ import annotations
import json
from dataclasses import dataclass
from pathlib import Path
from typing import Optional

@dataclass
class RoutingCoverageReport:
    period_start_utc:    float
    period_end_utc:      float
    total_requests:      int
    compliant_requests:  int
    violations:          int
    compliance_rate_pct: float
    regulation_gap:      Optional[str]   # set if coverage < required threshold

    @classmethod
    def from_log(
        cls,
        log_path: Path,
        period_start: float,
        period_end: float,
        required_pct: float = 100.0,
    ) -> "RoutingCoverageReport":
        total = compliant = 0
        violations = 0
        for line in log_path.read_text().splitlines():
            if not line.strip():
                continue
            rec = json.loads(line)
            ts = rec.get("timestamp_utc", 0)
            if not (period_start <= ts <= period_end):
                continue
            total += 1
            if rec.get("is_compliant"):
                compliant += 1
            else:
                violations += 1

        rate = (compliant / total * 100) if total else 0.0
        gap = None
        if rate < required_pct:
            gap = (
                f"Compliance rate {rate:.2f}% is below required {required_pct}%. "
                f"{violations} violations require exception documentation."
            )
        return cls(
            period_start_utc=period_start,
            period_end_utc=period_end,
            total_requests=total,
            compliant_requests=compliant,
            violations=violations,
            compliance_rate_pct=round(rate, 4),
            regulation_gap=gap,
        )

    def is_audit_ready(self, required_pct: float = 100.0) -> bool:
        return self.compliance_rate_pct >= required_pct and self.regulation_gap is None

    def summary_text(self) -> str:
        lines = [
            f"Audit period: {self.period_start_utc} – {self.period_end_utc} UTC",
            f"Total requests: {self.total_requests:,}",
            f"Compliant: {self.compliant_requests:,}  Violations: {self.violations}",
            f"Compliance rate: {self.compliance_rate_pct}%",
        ]
        if self.regulation_gap:
            lines.append(f"GAP: {self.regulation_gap}")
        else:
            lines.append("Status: AUDIT READY")
        return "\n".join(lines)
